                <p className="text-[#7589a3] text-base pt-1"> 10/10 correct</p>
            </div>
            <div>
                <h2 className="text-white text-2xl font-semibold"> You're a Legend</h2>
                <p className="text-[#7589a3] text-base pt-1">HTML Quiz</p>
            </div>
        </div>

