                    <h4 className="text-white text-lg font-semibold"> Question</h4>
                    <p className="text-base "> <span className="text-[#ef4343]">Your Anwser: var</span> <span className="text-white">||</span> <span className="text-[#81cba1]">Correct Answer: let</span></p>
